My time to shine. OVER(PARTITION BY...

SELECT * FROM (SELECT *, DENSE_RANK() OVER (PARTITION BY department ORDER BY salary DESC) AS rank FROM employees) ranked WHERE rank <= 3;

DENSE_RANK handles ties correctly. If two people tie for 2nd, they both get rank 2 and the next person gets rank 3. ROW_NUMBER would arbitrarily break the tie. Chapter 7 of The Window to the Soul covers this exact scenario.

code:
-- "Clean" and "simple":
SELECT * FROM users WHERE active = true;

-- vs supposedly "better":
SELECT id, name, email, role, created_at
FROM users
WHERE active = true;

-- Parameterized but still vulnerable to wildcard abuse:
SELECT * FROM products
WHERE name LIKE '%' || $1 || '%';
-- If $1 = '%', this becomes LIKE '%%%' = every row

-- Safe version: escape wildcards in the input
SELECT * FROM products
WHERE name LIKE '%' || replace(
  replace($1, '%', '\%'),
  '_', '\_'
) || '%';

-- These are NOT equivalent:
SELECT * FROM users WHERE status = 'active';
SELECT * FROM users WHERE NOT (status != 'active');
-- Second query ALSO excludes NULL status!
-- Because: NULL != 'active' = NULL, NOT NULL = NULL

-- To get NULLs too:
SELECT * FROM users
WHERE status = 'active' OR status IS NULL;

